module edge_detector(
	input wire clk,
	input wire reset,
	input wire signal,
	output reg edge_detected
);reg obf_signal_d;

	always @(posedge clk or posedge reset) begin
		if (reset) begin
			obf_signal_d <= 1'b0;
			edge_detected <= 1'b0;
		end else begin
			edge_detected <= signal & ~obf_signal_d;
			obf_signal_d <= signal;
		end
	end
endmodule
